SELECT n.id, n.title, n.author, n.description, n.cover_image_url, n.genre_id, g.name AS genre_name, n.created_at, ROUND(AVG(r.rating)::numeric, 1) AS average_rating, COUNT(r.id) AS review_count FROM novels n LEFT JOIN genres g ON n.genre_id = g.id LEFT JOIN reviews r ON n.id = r.novel_id
AND n.genre_id = #{genreId}
AND (n.title LIKE CONCAT('%', #{keyword}, '%') OR n.author LIKE CONCAT('%', #{keyword}, '%'))
GROUP BY n.id, n.title, n.author, n.description, n.cover_image_url, n.genre_id, g.name, n.created_at ORDER BY
average_rating DESC, review_count DESC, n.created_at DESC review_count DESC, average_rating DESC, n.created_at DESC n.created_at DESC
LIMIT #{size} OFFSET #{offset}

SELECT COUNT(*) FROM novels n
AND n.genre_id = #{genreId}
AND (n.title LIKE CONCAT('%', #{keyword}, '%') OR n.author LIKE CONCAT('%', #{keyword}, '%'))
